from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression is malformed or out of range."""


@dataclass(frozen=True)
class FieldSpec:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class CronField:
    spec: FieldSpec
    raw: str
    values: tuple[int, ...]

    def is_any(self) -> bool:
        return self.values == tuple(range(self.spec.minimum, self.spec.maximum + 1))

    def is_single(self) -> bool:
        return len(self.values) == 1

    def single_value(self) -> int:
        if not self.is_single():
            raise ValueError(f"{self.spec.name} is not a single value")
        return self.values[0]


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        if all(field.is_any() for field in self.fields()):
            return "Every minute"

        if self.minute.raw.startswith("*/") and self.rest_are_any("minute"):
            step = parse_positive_int(self.minute.raw[2:], "minute step")
            return f"Every {step} minutes"

        if self.minute.is_single() and self.minute.single_value() == 0:
            if self.hour.raw.startswith("*/") and self.rest_are_any("hour"):
                step = parse_positive_int(self.hour.raw[2:], "hour step")
                return f"Every {step} hours, on the hour"

        time_text = describe_time(self.hour, self.minute)

        if (
            self.minute.is_single()
            and self.minute.single_value() == 0
            and self.hour.is_single()
            and self.hour.single_value() == 0
            and self.day_of_month.is_single()
            and self.month.is_any()
            and self.day_of_week.is_any()
        ):
            day = ordinal(self.day_of_month.single_value())
            return f"At midnight on the {day} of every month"

        parts = [f"At {time_text}"]

        day_description = describe_day_restriction(self.day_of_month, self.day_of_week)
        if day_description:
            parts.append(day_description)

        month_description = describe_month_restriction(self.month)
        if month_description:
            parts.append(month_description)

        return " ".join(parts)

    def fields(self) -> tuple[CronField, CronField, CronField, CronField, CronField]:
        return (
            self.minute,
            self.hour,
            self.day_of_month,
            self.month,
            self.day_of_week,
        )

    def rest_are_any(self, except_field: str) -> bool:
        return all(
            field.is_any()
            for field in self.fields()
            if field.spec.name != except_field
        )


FIELD_SPECS: tuple[FieldSpec, ...] = (
    FieldSpec("minute", 0, 59),
    FieldSpec("hour", 0, 23),
    FieldSpec("day_of_month", 1, 31),
    FieldSpec("month", 1, 12),
    FieldSpec("day_of_week", 0, 6),
)

DAY_NAMES: tuple[str, ...] = (
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday",
)

MONTH_NAMES: tuple[str, ...] = (
    "",
    "January",
    "February",
    "March",
    "April",
    "May",
    "June",
    "July",
    "August",
    "September",
    "October",
    "November",
    "December",
)


def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise CronParseError(
            f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
        )

    parsed_fields = tuple(
        parse_field(raw_value, spec)
        for raw_value, spec in zip(parts, FIELD_SPECS)
    )

    return CronSchedule(
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
    )


def parse_field(raw_value: str, spec: FieldSpec) -> CronField:
    values: set[int] = set()

    for item in raw_value.split(","):
        if not item:
            raise CronParseError(f"Empty list item in {spec.name}: {raw_value!r}")

        values.update(parse_field_item(item, spec))

    return CronField(spec=spec, raw=raw_value, values=tuple(sorted(values)))


def parse_field_item(item: str, spec: FieldSpec) -> set[int]:
    base, step = split_step(item, spec)
    start, end = parse_base_range(base, spec)

    if step is None:
        step = 1

    return set(range(start, end + 1, step))


def split_step(item: str, spec: FieldSpec) -> tuple[str, int | None]:
    if "/" not in item:
        return item, None

    if item.count("/") > 1:
        raise CronParseError(f"Too many step separators in {spec.name}: {item!r}")

    base, step_text = item.split("/", 1)

    if not base:
        raise CronParseError(f"Missing step base in {spec.name}: {item!r}")

    step = parse_positive_int(step_text, f"{spec.name} step")
    return base, step


def parse_base_range(base: str, spec: FieldSpec) -> tuple[int, int]:
    if base == "*":
        return spec.minimum, spec.maximum

    if "-" in base:
        return parse_explicit_range(base, spec)

    value = parse_int_in_range(base, spec)
    return value, value


def parse_explicit_range(base: str, spec: FieldSpec) -> tuple[int, int]:
    if base.count("-") > 1:
        raise CronParseError(f"Too many range separators in {spec.name}: {base!r}")

    start_text, end_text = base.split("-", 1)
    start = parse_int_in_range(start_text, spec)
    end = parse_int_in_range(end_text, spec)

    if start > end:
        raise CronParseError(
            f"Invalid {spec.name} range {base!r}: start is greater than end"
        )

    return start, end


def parse_int_in_range(text: str, spec: FieldSpec) -> int:
    value = parse_non_negative_int(text, spec.name)

    if value < spec.minimum or value > spec.maximum:
        raise CronParseError(
            f"{spec.name} value {value} is outside "
            f"{spec.minimum}-{spec.maximum}"
        )

    return value


def parse_positive_int(text: str, label: str) -> int:
    value = parse_non_negative_int(text, label)

    if value <= 0:
        raise CronParseError(f"{label} must be greater than zero")

    return value


def parse_non_negative_int(text: str, label: str) -> int:
    if not text.isdigit():
        raise CronParseError(f"{label} must be a non-negative integer: {text!r}")

    return int(text)


def describe_time(hour: CronField, minute: CronField) -> str:
    if hour.is_single() and minute.is_single():
        hour_value = hour.single_value()
        minute_value = minute.single_value()

        if hour_value == 0 and minute_value == 0:
            return "midnight"

        return f"{hour_value:02d}:{minute_value:02d}"

    if hour.is_any() and minute.is_single():
        return f"{minute.single_value():02d} minutes past every hour"

    if minute.is_any() and hour.is_single():
        return f"every minute during {hour.single_value():02d}:00"

    return f"{describe_field_values(hour)}:{describe_field_values(minute)}"


def describe_day_restriction(day_of_month: CronField, day_of_week: CronField) -> str:
    if day_of_month.is_any() and day_of_week.is_any():
        return ""

    if not day_of_week.is_any():
        return f"on {describe_weekdays(day_of_week)}"

    if day_of_month.is_single():
        return f"on the {ordinal(day_of_month.single_value())} of every month"

    return f"on days {format_number_list(day_of_month.values)} of every month"


def describe_month_restriction(month: CronField) -> str:
    if month.is_any():
        return ""

    return f"in {format_list(MONTH_NAMES[value] for value in month.values)}"


def describe_weekdays(day_of_week: CronField) -> str:
    if is_contiguous(day_of_week.values):
        first = DAY_NAMES[day_of_week.values[0]]
        last = DAY_NAMES[day_of_week.values[-1]]

        if first == last:
            return first

        return f"{first} through {last}"

    return format_list(DAY_NAMES[value] for value in day_of_week.values)


def describe_field_values(field: CronField) -> str:
    if field.is_any():
        return "*"

    if field.is_single():
        return str(field.single_value())

    return format_number_list(field.values)


def is_contiguous(values: tuple[int, ...]) -> bool:
    return values == tuple(range(values[0], values[-1] + 1))


def format_number_list(values: Iterable[int]) -> str:
    return format_list(str(value) for value in values)


def format_list(values: Iterable[str]) -> str:
    items = list(values)

    if not items:
        return ""

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


